      page.getByRole("checkbox", { name: /Mark "Buy groceries"/ })
    ).toBeVisible();
  });

  test("delete button has aria-label", async ({ page }) => {
    await expect(
      page.getByRole("button", { name: /Delete "Buy groceries"/ })
    ).toBeVisible();
  });
});
